using UnityEngine;

/// <summary>
/// Balançar em cipós (P8 — Gibão/Babuíno): física de pêndulo simples.
///
/// Uso: dentro da área de um ClimbableSurface do tipo 'CipoBalanco', apertar
/// Interagir (toque) agarra-se ao ponto do cipó — toggle, igual a Corda/Escada
/// (ver ClimbAbility.TryToggleVineAttach, que IGNORA 'CipoBalanco' e deixa
/// para este script via AbilityRouter.OnInteractPressed). Enquanto agarrado:
///
/// - O input horizontal "empurra" o balanço (ganha/perde energia/amplitude).
/// - A gravidade da própria forma traz o pêndulo de volta para baixo.
/// - Apertar Interagir de novo SOLTA — o player é lançado com a velocidade
///   tangencial do balanço nesse instante ("física normal", igual ao Drop/
///   Throw de objectos: o momentum do balanço vira força de disparo).
///
/// Diferença para Corda/Escada (ClimbAbility): aquelas SOBEM/DESCEM ao longo
/// da superfície (vertical, controlado pelo input); este BALANÇA em arco
/// (pêndulo) a partir de um ponto fixo — o transform do ClimbableSurface.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class SwingAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Detecção de cipó (CipoBalanco)")]
    [Tooltip("Offset (a partir do transform do player) do centro da caixa de procura.")]
    [SerializeField] private Vector2 checkOffset = Vector2.zero;

    [Tooltip("Tamanho da caixa de procura de cipós de balanço.")]
    [SerializeField] private Vector2 checkSize = new Vector2(1f, 1.2f);

    [Header("Balanço (pêndulo)")]
    [Tooltip("Aceleração angular (rad/s²) aplicada pelo input horizontal — 'empurra' o balanço para ganhar/perder amplitude.")]
    public float swingInputForce = 8f;

    [Tooltip("Velocidade angular máxima (rad/s), antes do multiplicador da superfície.")]
    public float maxAngularSpeed = 4f;

    [Tooltip("Amortecimento por segundo (0 = sem perda de energia; 1 = pára quase imediatamente).")]
    [Range(0f, 1f)] public float angularDamping = 0.05f;

    [Tooltip("Comprimento mínimo do cipó (evita pêndulos demasiado curtos/instáveis).")]
    public float minRopeLength = 0.5f;

    [Header("Input")]
    [Tooltip("Auto-preenchido.")]
    [SerializeField] private PlayerInputRouter input;

    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    // Buffer NonAlloc reutilizável — evita alocação em TryToggleSwingAttach.
    private static readonly Collider2D[] _swingBuffer = new Collider2D[8];

    private AnimalFormData form;
    private bool enabledForForm;

    private bool isSwinging;
    private Transform anchor;
    private float ropeLength;
    private float angle;            // radianos a partir da vertical (0 = pendente directamente abaixo do anchor)
    private float angularVelocity;  // rad/s
    private float speedMultiplier = 1f;
    private float gravityBeforeSwing;

    /// <summary>true enquanto o player está agarrado a um cipó de balanço.</summary>
    public bool IsSwinging => isSwinging;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();

        if (input == null) input = GetComponent<PlayerInputRouter>();
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;

        // Mesmo critério que Corda/Escada (ClimbAbility): canClimb OU canGrab.
        enabledForForm = form != null && (form.canClimb || form.canGrab);

        if (!enabledForForm) StopSwing();
    }

    /// <summary>
    /// Chamado pelo AbilityRouter ao apertar Interagir (toque), DEPOIS de
    /// ClimbAbility.TryToggleVineAttach (que ignora 'CipoBalanco'). Agarra-se
    /// a um cipó próximo, ou larga (lançando o player) se já estiver agarrado.
    /// Devolve true se consumiu o toque.
    /// </summary>
    public bool TryToggleSwingAttach()
    {
        if (isSwinging)
        {
            StopSwing();
            return true;
        }

        if (!enabledForForm) return false;

        Vector2 center = (Vector2)transform.position + checkOffset;
        int count = Physics2D.OverlapBoxNonAlloc(center, checkSize, 0f, _swingBuffer);

        for (int i = 0; i < count; i++)
        {
            var hit = _swingBuffer[i];
            if (hit == null || hit.gameObject == gameObject) continue;

            var surface = hit.GetComponent<ClimbableSurface>();
            if (surface == null || surface.kind != ClimbableKind.CipoBalanco) continue;
            if (!surface.AllowsForm(form)) continue;

            StartSwing(hit.transform, surface.climbSpeedMultiplier);
            return true;
        }

        return false;
    }

    private void StartSwing(Transform vineAnchor, float multiplier)
    {
        isSwinging = true;
        anchor = vineAnchor;
        speedMultiplier = Mathf.Max(0.1f, multiplier);
        gravityBeforeSwing = rb.gravityScale;

        Vector2 rel = (Vector2)transform.position - (Vector2)anchor.position;
        ropeLength = Mathf.Max(minRopeLength, rel.magnitude);
        angle = Mathf.Atan2(rel.x, -rel.y); // posição: x = L*sin(angle), y = -L*cos(angle)

        // Preserva o movimento horizontal actual como velocidade angular inicial
        // (agarrar o cipó "em corrida" já dá balanço, sem ressalto brusco).
        float cosA = Mathf.Cos(angle);
        angularVelocity = Mathf.Abs(cosA) > 0.05f ? rb.linearVelocity.x / (ropeLength * cosA) : 0f;
        angularVelocity = Mathf.Clamp(angularVelocity, -maxAngularSpeed * speedMultiplier, maxAngularSpeed * speedMultiplier);

        rb.gravityScale = 0f;
        rb.linearVelocity = Vector2.zero;
        motor.SetMovementLocked(true, this);
    }

    /// <summary>Larga o cipó: lança o player com a velocidade tangencial do balanço nesse instante.</summary>
    public void StopSwing()
    {
        if (!isSwinging) return;

        isSwinging = false;

        float tangentialSpeed = ropeLength * angularVelocity;
        rb.linearVelocity = new Vector2(Mathf.Cos(angle), Mathf.Sin(angle)) * tangentialSpeed;

        rb.gravityScale = gravityBeforeSwing;
        anchor = null;
        motor.SetMovementLocked(false, this);
    }

    private void FixedUpdate()
    {
        if (!isSwinging) return;

        if (anchor == null)
        {
            StopSwing();
            return;
        }

        float dt = Time.fixedDeltaTime;

        // Gravidade (da própria forma) traz o pêndulo para baixo (angle -> 0).
        float gravity = Mathf.Abs(Physics2D.gravity.y) * Mathf.Max(0.01f, gravityBeforeSwing);
        float angularAccel = -(gravity / ropeLength) * Mathf.Sin(angle);

        // Input horizontal "empurra" o balanço.
        float h = input != null ? input.Move.x : 0f;
        angularAccel += h * swingInputForce * speedMultiplier / ropeLength;

        angularVelocity += angularAccel * dt;
        angularVelocity *= 1f - angularDamping;

        float maxSpeed = maxAngularSpeed * speedMultiplier;
        angularVelocity = Mathf.Clamp(angularVelocity, -maxSpeed, maxSpeed);

        angle += angularVelocity * dt;

        Vector2 newRel = new Vector2(Mathf.Sin(angle), -Mathf.Cos(angle)) * ropeLength;
        rb.MovePosition((Vector2)anchor.position + newRel);

        // Velocidade tangencial actual — usada pela animação (Speed/FacingSign)
        // e como velocidade de lançamento se soltar nesta posição.
        float tangentialSpeed = ropeLength * angularVelocity;
        rb.linearVelocity = new Vector2(Mathf.Cos(angle), Mathf.Sin(angle)) * tangentialSpeed;
    }

    private void OnDisable() => StopSwing();

    // ---- IAbility (item 8) ----
    // Tal como Climb, Swing entra/sai via Interagir (TryToggleSwingAttach), não
    // pelo botão de habilidade — Activate/Release ficam sem efeito.
    void IAbility.Activate() { }
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) => StopSwing();
    public float CooldownRemaining => 0f;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    // Sem cooldown: a HUD não mostra indicador para esta habilidade.
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm;
    bool IAbility.IsActive => isSwinging;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.4f, 0.8f, 1f, 0.5f);
        Gizmos.DrawWireCube((Vector2)transform.position + checkOffset, checkSize);

        if (isSwinging && anchor != null)
        {
            Gizmos.color = Color.cyan;
            Gizmos.DrawLine(anchor.position, transform.position);
        }
    }
}
